/**
 * Revoke all pairing codes for a tenant
 * Used when logging out or resetting
 */
export function revokeTenantCodes(tenantId: string): number {
  let count = 0;
  for (const [code, pairing] of pairingCodes.entries()) {
    if (pairing.tenantId === tenantId) {
      pairingCodes.delete(code);
      count++;
    }
  }
  return count;
}
